const input = $input.first();
const incomingJson = input.json || {};
const body = (incomingJson.body && typeof incomingJson.body === 'object') ? incomingJson.body : incomingJson;
const binary = input.binary || {};
const binaryKeys = Object.keys(binary);

const workflowId = body.workflowId || 'default-workflow';
const metadata = (body.metadata && typeof body.metadata === 'object') ? body.metadata : {};
const traceId = (typeof metadata.traceId === 'string' && metadata.traceId)
  ? metadata.traceId
  : (typeof body.traceId === 'string' && body.traceId)
    ? body.traceId
    : `trace_${Date.now()}`;
const executionId = `exec_${Date.now()}`;

const parsedLlmConfig =
  body.llmConfig && typeof body.llmConfig === 'object'
    ? body.llmConfig
    : typeof body.llmConfig === 'string'
      ? (() => {
          try {
            const parsed = JSON.parse(body.llmConfig);
            return parsed && typeof parsed === 'object' ? parsed : {};
          } catch (_jsonError) {
            return {};
          }
        })()
      : {};

let envEndpoint = '';
let envApiKey = '';
let envModel = '';
try {
  envEndpoint = $env.INVOICE_LLM_ENDPOINT || '';
  envApiKey = $env.INVOICE_LLM_API_KEY || '';
  envModel = $env.INVOICE_LLM_MODEL || '';
} catch (_envError) {
  // Env access can be blocked in some n8n deployments.
}

const endpoint =
  (typeof body.llmEndpoint === 'string' && body.llmEndpoint) ||
  (typeof parsedLlmConfig.endpoint === 'string' && parsedLlmConfig.endpoint) ||
  envEndpoint ||
  'https://api.openai.com/v1/chat/completions';

const apiKey =
  (typeof body.llmApiKey === 'string' && body.llmApiKey) ||
  (typeof parsedLlmConfig.apiKey === 'string' && parsedLlmConfig.apiKey) ||
  envApiKey ||
  '';

const model =
  (typeof body.llmModel === 'string' && body.llmModel) ||
  (typeof parsedLlmConfig.model === 'string' && parsedLlmConfig.model) ||
  envModel ||
  'gpt-4o-mini';

const ocrPrompt = [
  'You are an invoice OCR extraction engine.',
  'Return ONLY JSON with fields:',
  '{',
  '  "supplier_name": string|null,',
  '  "raw_merchant": string|null,',
  '  "abn": string|null,',
  '  "tax_invoice_flag": boolean,',
  '  "invoice_number": string|null,',
  '  "invoice_date": string|null,',
  '  "due_date": string|null,',
  '  "currency": string|null,',
  '  "total": number|null,',
  '  "gst_amount": number|null,',
  '  "gst_status": "explicit_amount"|"included_unknown_amount"|"no_gst_indicated"|"unknown"|"mixed",',
  '  "line_items": Array<{description:string,quantity:number,unit_price:number,total:number}>,',
  '  "confidence": {supplier_name:number,invoice_date:number,total:number,gst:number,abn:number},',
  '  "needs_human_review": boolean,',
  '  "reasons": string[]',
  '}',
  'If missing, use null and set needs_human_review=true with reason.'
].join('\n');

const toNumber = value => {
  const n = Number(value);
  return Number.isFinite(n) ? n : null;
};

const normalizeGstStatus = value => {
  const allowed = [
    'explicit_amount',
    'included_unknown_amount',
    'no_gst_indicated',
    'unknown',
    'mixed',
  ];
  return typeof value === 'string' && allowed.includes(value)
    ? value
    : 'unknown';
};

const fallbackExtraction = (doc, reason) => ({
  raw_merchant: doc.fileName || null,
  supplier_name: null,
  abn: null,
  tax_invoice_flag: false,
  invoice_number: null,
  invoice_date: null,
  due_date: null,
  currency: 'AUD',
  total: null,
  gst_amount: null,
  gst_status: 'unknown',
  line_items: [],
  confidence: {
    supplier_name: 0.1,
    invoice_date: 0.1,
    total: 0.1,
    gst: 0.1,
    abn: 0.1,
  },
  needs_human_review: true,
  reasons: [reason],
});

const safeJsonParse = text => {
  try {
    return JSON.parse(text);
  } catch (_err) {
    const fenceMatch = text.match(/```(?:json)?\s*([\s\S]*?)\s*```/i);
    if (fenceMatch && fenceMatch[1]) {
      return JSON.parse(fenceMatch[1]);
    }
    const objMatch = text.match(/\{[\s\S]*\}/);
    if (objMatch) {
      return JSON.parse(objMatch[0]);
    }
    throw new Error('LLM output is not valid JSON');
  }
};

const normalizeExtraction = (parsed, doc, reasonIfEmpty = null) => {
  const source = parsed && typeof parsed === 'object' ? parsed : {};
  const reasons = Array.isArray(source.reasons)
    ? source.reasons.filter(item => typeof item === 'string')
    : [];
  if (reasonIfEmpty && reasons.length === 0) {
    reasons.push(reasonIfEmpty);
  }

  const lineItems = Array.isArray(source.line_items)
    ? source.line_items
        .filter(item => item && typeof item === 'object')
        .map(item => ({
          description:
            typeof item.description === 'string' && item.description
              ? item.description
              : 'Line item',
          quantity: Number.isFinite(Number(item.quantity))
            ? Number(item.quantity)
            : 1,
          unit_price: Number.isFinite(Number(item.unit_price))
            ? Number(item.unit_price)
            : 0,
          total: Number.isFinite(Number(item.total))
            ? Number(item.total)
            : (Number.isFinite(Number(item.quantity)) ? Number(item.quantity) : 1) *
              (Number.isFinite(Number(item.unit_price))
                ? Number(item.unit_price)
                : 0),
        }))
    : [];

  const confidence =
    source.confidence && typeof source.confidence === 'object'
      ? source.confidence
      : {};

  return {
    raw_merchant:
      typeof source.raw_merchant === 'string' && source.raw_merchant
        ? source.raw_merchant
        : doc.fileName || null,
    supplier_name:
      typeof source.supplier_name === 'string' && source.supplier_name
        ? source.supplier_name
        : null,
    abn: typeof source.abn === 'string' && source.abn ? source.abn : null,
    tax_invoice_flag: Boolean(source.tax_invoice_flag),
    invoice_number:
      typeof source.invoice_number === 'string' && source.invoice_number
        ? source.invoice_number
        : null,
    invoice_date:
      typeof source.invoice_date === 'string' && source.invoice_date
        ? source.invoice_date
        : null,
    due_date:
      typeof source.due_date === 'string' && source.due_date
        ? source.due_date
        : null,
    currency:
      typeof source.currency === 'string' && source.currency
        ? source.currency
        : 'AUD',
    total: toNumber(source.total),
    gst_amount: toNumber(source.gst_amount),
    gst_status: normalizeGstStatus(source.gst_status),
    line_items: lineItems,
    confidence: {
      supplier_name: Number.isFinite(Number(confidence.supplier_name))
        ? Number(confidence.supplier_name)
        : 0.5,
      invoice_date: Number.isFinite(Number(confidence.invoice_date))
        ? Number(confidence.invoice_date)
        : 0.5,
      total: Number.isFinite(Number(confidence.total))
        ? Number(confidence.total)
        : 0.5,
      gst: Number.isFinite(Number(confidence.gst))
        ? Number(confidence.gst)
        : 0.4,
      abn: Number.isFinite(Number(confidence.abn))
        ? Number(confidence.abn)
        : 0.2,
    },
    needs_human_review:
      typeof source.needs_human_review === 'boolean'
        ? source.needs_human_review
        : reasons.length > 0,
    reasons,
  };
};

const documents = binaryKeys.map((key, index) => {
  const file = binary[key] || {};
  return {
    key,
    index,
    fileName: file.fileName || `file_${index + 1}`,
    mimeType: file.mimeType || file.fileType || 'application/octet-stream',
    data: file.data || '',
  };
});

if (documents.length === 0) {
  return [
    {
      json: {
        executionId,
        workflowId,
        traceId,
        hasBusinessData: false,
        summary: {
          totalItems: 0,
          ocrDocuments: 0,
          extractedRecords: 0,
          googleSheetsRecords: 0,
          successfulExtractions: 0,
          failedExtractions: 0,
          duplicateRecords: 0,
          qualityIssues: 0,
          successRate: '0%',
          uniqueInvoices: 0,
        },
        results: [],
        recommendations: ['No files received by webhook.'],
      },
    },
  ];
}

const callLlmForDocument = async doc => {
  const isImage =
    typeof doc.mimeType === 'string' && doc.mimeType.startsWith('image/');
  if (!isImage) {
    return fallbackExtraction(
      doc,
      `Unsupported MIME type for direct vision OCR: ${doc.mimeType}`
    );
  }

  if (!apiKey) {
    return fallbackExtraction(
      doc,
      'Missing LLM API key (set llmApiKey, llmConfig.apiKey, or env INVOICE_LLM_API_KEY)'
    );
  }

  const requestBody = {
    model,
    temperature: 0,
    messages: [
      {
        role: 'system',
        content: 'You extract structured invoice data from images.',
      },
      {
        role: 'user',
        content: [
          { type: 'text', text: ocrPrompt },
          {
            type: 'image_url',
            image_url: { url: `data:${doc.mimeType};base64,${doc.data}` },
          },
        ],
      },
    ],
  };

  let payload;
  try {
    payload = await this.helpers.httpRequest({
      method: 'POST',
      url: endpoint,
      headers: {
        'Content-Type': 'application/json',
        Authorization: `Bearer ${apiKey}`,
      },
      body: requestBody,
      json: true,
    });
  } catch (error) {
    const errMsg =
      error && typeof error.message === 'string'
        ? error.message
        : String(error);
    return fallbackExtraction(
      doc,
      `LLM API error: ${errMsg.slice(0, 160)}`
    );
  }
  const content = payload?.choices?.[0]?.message?.content;
  const textContent = Array.isArray(content)
    ? content
        .map(part => (typeof part?.text === 'string' ? part.text : ''))
        .join('\n')
    : typeof content === 'string'
      ? content
      : '';

  if (!textContent) {
    return fallbackExtraction(doc, 'LLM returned empty content');
  }

  const parsed = safeJsonParse(textContent);
  return normalizeExtraction(parsed, doc);
};

const extractedList = [];
for (const doc of documents) {
  try {
    const extracted = await callLlmForDocument(doc);
    extractedList.push({ doc, extracted });
  } catch (error) {
    extractedList.push({
      doc,
      extracted: fallbackExtraction(
        doc,
        error instanceof Error ? error.message : 'Unknown extraction failure'
      ),
    });
  }
}

const successfulExtractions = extractedList.filter(
  item => !item.extracted.needs_human_review
).length;
const failedExtractions = extractedList.length - successfulExtractions;
const totalAmount = extractedList.reduce(
  (sum, item) => sum + (Number(item.extracted.total) || 0),
  0
);

const resultRows = extractedList.map((item, index) => {
  const extraction = item.extracted;
  const lineTotal = Array.isArray(extraction.line_items)
    ? extraction.line_items.reduce((s, row) => s + (Number(row.total) || 0), 0)
    : 0;
  return {
    index,
    summary: {
      totalItems: 1,
      ocrDocuments: 1,
      extractedRecords: 1,
      googleSheetsRecords: 0,
      successfulExtractions: extraction.needs_human_review ? 0 : 1,
      failedExtractions: extraction.needs_human_review ? 1 : 0,
      duplicateRecords: 0,
      qualityIssues: extraction.reasons.length,
      successRate: extraction.needs_human_review ? '0%' : '100%',
      uniqueInvoices: extraction.invoice_number ? 1 : 0,
    },
    financialSummary: {
      totalAmount: String(Number(extraction.total) || lineTotal || 0),
      averageAmount: String(Number(extraction.total) || lineTotal || 0),
      minAmount: String(Number(extraction.total) || lineTotal || 0),
      maxAmount: String(Number(extraction.total) || lineTotal || 0),
      medianAmount: String(Number(extraction.total) || lineTotal || 0),
      count: 1,
    },
    processingDetails: {
      successfulInvoices: extraction.invoice_number
        ? [
            {
              invoiceNumber: extraction.invoice_number,
              vendorName:
                extraction.supplier_name ||
                extraction.raw_merchant ||
                item.doc.fileName,
              totalAmount: Number(extraction.total) || lineTotal || 0,
              index,
            },
          ]
        : [],
      failedExtractions: extraction.needs_human_review
        ? [
            {
              index,
              error: extraction.reasons.join('; ') || 'Manual review needed',
            },
          ]
        : [],
      qualityIssues: extraction.reasons.map(reason => ({
        index,
        invoiceNumber: extraction.invoice_number || '',
        issueType: 'ocr',
        issue: reason,
      })),
      duplicates: [],
    },
    qualityMetrics: {
      averageConfidence:
        ((Number(extraction.confidence.supplier_name) || 0) +
          (Number(extraction.confidence.invoice_date) || 0) +
          (Number(extraction.confidence.total) || 0) +
          (Number(extraction.confidence.gst) || 0) +
          (Number(extraction.confidence.abn) || 0)) /
        5,
      highConfidenceRecords: extraction.needs_human_review ? 0 : 1,
      mediumConfidenceRecords: extraction.needs_human_review ? 1 : 0,
      lowConfidenceRecords: 0,
      confidenceDistribution: [],
    },
    recommendations:
      extraction.reasons.length > 0
        ? extraction.reasons
        : ['Extraction looks good.'],
    extractedData: extraction,
  };
});

const firstExtraction = resultRows[0]?.extractedData || null;

return [
  {
    json: {
      executionId,
      workflowId,
      traceId,
      hasBusinessData: true,
      summary: {
        totalItems: extractedList.length,
        ocrDocuments: extractedList.length,
        extractedRecords: extractedList.length,
        googleSheetsRecords: 0,
        successfulExtractions,
        failedExtractions,
        duplicateRecords: 0,
        qualityIssues: resultRows.reduce(
          (sum, row) => sum + (row.processingDetails.qualityIssues?.length || 0),
          0
        ),
        successRate:
          extractedList.length > 0
            ? `${Math.round((successfulExtractions / extractedList.length) * 100)}%`
            : '0%',
        uniqueInvoices: new Set(
          resultRows
            .map(row => row.extractedData.invoice_number)
            .filter(Boolean)
        ).size,
      },
      financialSummary: {
        totalAmount: String(totalAmount),
        averageAmount:
          extractedList.length > 0
            ? String(totalAmount / extractedList.length)
            : '0',
        minAmount:
          extractedList.length > 0
            ? String(
                Math.min(
                  ...resultRows.map(
                    row => Number(row.financialSummary.totalAmount) || 0
                  )
                )
              )
            : '0',
        maxAmount:
          extractedList.length > 0
            ? String(
                Math.max(
                  ...resultRows.map(
                    row => Number(row.financialSummary.totalAmount) || 0
                  )
                )
              )
            : '0',
        medianAmount:
          extractedList.length > 0
            ? String(
                resultRows
                  .map(row => Number(row.financialSummary.totalAmount) || 0)
                  .sort((a, b) => a - b)[Math.floor(extractedList.length / 2)] || 0
              )
            : '0',
        count: extractedList.length,
      },
      processingDetails: {
        successfulInvoices: resultRows.flatMap(
          row => row.processingDetails.successfulInvoices || []
        ),
        failedExtractions: resultRows.flatMap(
          row => row.processingDetails.failedExtractions || []
        ),
        qualityIssues: resultRows.flatMap(
          row => row.processingDetails.qualityIssues || []
        ),
        duplicates: [],
      },
      qualityMetrics: {
        averageConfidence:
          resultRows.length > 0
            ? resultRows.reduce(
                (sum, row) => sum + (Number(row.qualityMetrics.averageConfidence) || 0),
                0
              ) / resultRows.length
            : 0,
        highConfidenceRecords: resultRows.filter(
          row => Number(row.qualityMetrics.averageConfidence) >= 0.8
        ).length,
        mediumConfidenceRecords: resultRows.filter(
          row =>
            Number(row.qualityMetrics.averageConfidence) >= 0.5 &&
            Number(row.qualityMetrics.averageConfidence) < 0.8
        ).length,
        lowConfidenceRecords: resultRows.filter(
          row => Number(row.qualityMetrics.averageConfidence) < 0.5
        ).length,
        confidenceDistribution: [],
      },
      recommendations: [
        'Pass llmApiKey/llmEndpoint/llmModel or llmConfig, or set env INVOICE_LLM_* in n8n.',
        'For PDF files, add a PDF-to-image OCR preprocessor before this node.',
        'Map extracted fields to your backend /invoice-ocr/{workflowId}/results storage if needed.',
      ],
      results: resultRows,
      data: firstExtraction,
    },
  },
];
